     1→import styled, { css } from 'styled-components'
     2→import { Link, useNavigate } from 'react-router-dom'
     3→import useDarkMode from 'use-dark-mode'
     4→
     5→import { useAppDispatch, useAppSelector } from '../../app-state'
     6→import {
     7→  CartItem,
     8→  saveItemAction,
     9→  selectCartItems,
    10→  selectCartTotal,
    11→  selectCartVisibility,
    12→  toggleVisibilityAction,
    13→} from '../../app-state/cart'
    14→import { breakpoints } from '../../styles/breakpoints'
    15→import { ShoppingCartMenu } from '../ShoppingCartMenu'
    16→import { Button } from '../Button'
    17→import { toCurrency } from '../../helpers'
    18→import { Body } from '../typography/Body'
    19→import { Logo } from '../Logo'
    20→
    21→export const HeaderContainer = styled.div<{ $sticky: boolean }>(
    22→  ({ $sticky, theme: { color } }) => css`
    23→    display: flex;
    24→    justify-content: space-between;
    25→    height: 56px;
    26→    border-bottom: 1px solid ${color.headerBorder};
    27→    top: 0;
    28→    left: 0;
    29→    position: sticky;
    30→    background: ${color.headerBackground};
    31→    z-index: 2;
    32→    width: 100%;
    33→    padding: 0 1.5rem;
    34→
    35→    @media ${breakpoints.S} {
    36→      padding: 0 4rem;
    37→    }
    38→
    39→    @media ${breakpoints.M} {
    40→      position: ${$sticky ? 'sticky' : 'relative'};
    41→      height: 72px;
    42→    }
    43→  `
    44→)
    45→
    46→export const LogoContainer = styled(Link)`
    47→  width: 40px;
    48→  display: flex;
    49→  padding-left: 1rem;
    50→
    51→  & img {
    52→    width: 100%;
    53→  }
    54→
    55→  @media screen and (max-width: 800px) {
    56→    width: 30px;
    57→    padding: 0;
    58→  }
    59→`
    60→
    61→export const OptionsContainer = styled.div`
    62→  width: 50%;
    63→  height: 100%;
    64→  display: flex;
    65→  align-items: center;
    66→  justify-content: flex-end;
    67→
    68→  .navigation-items {
    69→    display: none;
    70→  }
    71→
    72→  a {
    73→    margin-right: 0.5rem;
    74→  }
    75→
    76→  @media ${breakpoints.M} {
    77→    .navigation-items {
    78→      display: contents;
    79→    }
    80→    width: 80%;
    81→  }
    82→`
    83→
    84→export const CartText = styled(Body)(
    85→  ({ theme: { color } }) => css`
    86→    display: none;
    87→    @media ${breakpoints.M} {
    88→      display: inline-block;
    89→      color: ${color.cartButtonText};
    90→      margin-right: 0.25rem;
    91→    }
    92→  `
    93→)
    94→
    95→export const CartTotal = styled(Body)(
    96→  ({ theme: { color } }) => css`
    97→    display: inline-block;
    98→    color: ${color.buttonText};
    99→  `
   100→)
   101→
   102→const ThemeToggle = () => {
   103→  const darkMode = useDarkMode(false, { global: globalThis.window })
   104→  return (
   105→    <Button
   106→      round
   107→      clear
   108→      aria-label={`turn on ${darkMode.value ? 'light' : 'dark'} mode`}
   109→      icon={darkMode.value ? 'moon' : 'sun'}
   110→      onClick={darkMode.toggle}
   111→    />
   112→  )
   113→}
   114→
   115→type HeaderComponentProps = {
   116→  isCartVisible?: boolean
   117→  cartItems?: CartItem[]
   118→  totalPrice?: number
   119→  logoOnly?: boolean
   120→  sticky?: boolean
   121→  toggleCartVisibility?: () => void
   122→  goToCheckout?: () => void
   123→  saveItem?: (item: CartItem) => void
   124→}
   125→
   126→export const HeaderComponent = ({
   127→  isCartVisible = false,
   128→  logoOnly = false,
   129→  sticky = false,
   130→  totalPrice = 0,
   131→  cartItems = [],
   132→  toggleCartVisibility = () => {},
   133→  goToCheckout = () => {},
   134→  saveItem = () => {},
   135→}: HeaderComponentProps) => (
   136→  <HeaderContainer data-testid="header" $sticky={sticky}>
   137→    <LogoContainer to="/" aria-label="go to home page">
   138→      <Logo />
   139→    </LogoContainer>
   140→    {!logoOnly && (
   141→      <>
   142→        <OptionsContainer>
   143→          <span className="navigation-items">
   144→            <ThemeToggle />
   145→            <Link to="/" tabIndex={-1}>
   146→              <Button clear>Home</Button>
   147→            </Link>
   148→            <Link to="/categories" tabIndex={-1}>
   149→              <Button clear>All restaurants</Button>
   150→            </Link>
   151→          </span>
   152→          <Button aria-label="food cart" icon="cart" onClick={toggleCartVisibility}>
   153→            {totalPrice > 0 && (
   154→              <>
